function Nav() {
  const [scrolled, setScrolled] = useState(false);
  const [open, setOpen] = useState(false);
  useEffect(() => {
    const h = () => setScrolled(window.scrollY > 50);
    window.addEventListener("scroll", h);
    return () => window.removeEventListener("scroll", h);
  }, []);
  const links = [
    ["Sobre", "#sobre"], ["Serviços", "#servicos"], ["Resultados", "#resultados"],
    ["Empresas", "#empresas"], ["Contato", "#contato"]
  ];
  return (
    <nav style={{
      position: "fixed", top: 0, left: 0, right: 0, zIndex: 999,
      background: scrolled ? "rgba(12,12,20,0.95)" : "transparent",
      backdropFilter: scrolled ? "blur(16px)" : "none",
      borderBottom: scrolled ? `1px solid ${C.goldMuted}` : "none",
      transition: "all 0.4s ease",
    }}>
      <div style={{
        maxWidth: 1240, margin: "0 auto", padding: "0 28px",
        display: "flex", justifyContent: "space-between", alignItems: "center",
        height: scrolled ? 60 : 76, transition: "height 0.3s",
      }}>
        <div>
          <span style={{ fontFamily: "var(--ff-display)", fontSize: 18, fontWeight: 700, color: C.cream, letterSpacing: 2 }}>
            IA PRODUTIVA
          </span>
          <span style={{ fontFamily: "var(--ff-body)", fontSize: 11, color: C.goldLight, marginLeft: 8, opacity: 0.6, letterSpacing: 1 }}>
            por Sulana Mara
          </span>
        </div>
        <div className="nav-desktop" style={{ display: "flex", gap: 28, alignItems: "center" }}>
          {links.map(([l, h]) => (
            <a key={l} href={h} style={{
              color: C.goldLight, textDecoration: "none", fontSize: 12, fontFamily: "var(--ff-body)",
              letterSpacing: 1.8, textTransform: "uppercase", fontWeight: 500, transition: "color 0.3s",
            }} onMouseEnter={e => e.target.style.color = C.gold} onMouseLeave={e => e.target.style.color = C.goldLight}>
              {l}
            </a>
          ))}
          <a href="#contato" style={{
            padding: "10px 24px", background: C.gold, color: C.dark,
            fontFamily: "var(--ff-body)", fontSize: 11, fontWeight: 700, letterSpacing: 1.5,
            textTransform: "uppercase", textDecoration: "none", transition: "all 0.3s",
          }} onMouseEnter={e => e.target.style.background = C.goldLight} onMouseLeave={e => e.target.style.background = C.gold}>
            Falar com Sulana
          </a>
        </div>
        <button className="nav-mobile-btn" onClick={() => setOpen(!open)} style={{
          display: "none", background: "none", border: "none", color: C.gold, fontSize: 26, cursor: "pointer",
        }}>{open ? "✕" : "☰"}</button>
      </div>
      {open && (
        <div className="nav-mobile-menu" style={{ background: "rgba(12,12,20,0.98)", padding: "12px 28px 24px" }}>
          {links.map(([l, h]) => (
            <a key={l} href={h} onClick={() => setOpen(false)} style={{
              display: "block", color: C.goldLight, textDecoration: "none", fontSize: 14,
              padding: "14px 0", borderBottom: `1px solid rgba(201,168,76,0.08)`,
              fontFamily: "var(--ff-body)", letterSpacing: 1,
            }}>{l}</a>
          ))}
        </div>
      )}
    </nav>
  );
}

